"""
AWS S3 Bucket File Lister - Demo Script

SETUP (choose one, takes < 1 minute):

Option A: Set environment variables before running:
    Windows:  set AWS_ACCESS_KEY_ID=your_key && set AWS_SECRET_ACCESS_KEY=your_secret
    Mac/Linux: export AWS_ACCESS_KEY_ID=your_key && export AWS_SECRET_ACCESS_KEY=your_secret

Option B: The script will prompt you to enter credentials interactively.

Option C: Place credentials in ~/.aws/credentials file (AWS CLI style).
"""

import sys

try:
    import boto3
    from botocore.exceptions import ClientError, NoCredentialsError
except ImportError:
    print("Installing required package: boto3")
    import subprocess
    subprocess.check_call([sys.executable, "-m", "pip", "install", "boto3"])
    import boto3
    from botocore.exceptions import ClientError, NoCredentialsError


BUCKET_NAME = "demo-bucket"


def get_s3_client():
    """
    Try environment variables / AWS config first.
    Fall back to interactive prompt if no credentials are found.
    """
    # First, try default credential chain (env vars, ~/.aws/credentials, IAM role, etc.)
    try:
        client = boto3.client("s3")
        # Test if credentials are actually available by making a lightweight call
        client.head_bucket(Bucket=BUCKET_NAME)
        print("[+] Using credentials from environment / AWS config.")
        return client
    except NoCredentialsError:
        pass
    except ClientError:
        # Credentials exist but might be wrong, or bucket issue — still return client
        print("[+] Using credentials from environment / AWS config.")
        return client

    # Fall back to interactive prompt
    print("No AWS credentials found in environment. Please enter them now.")
    print("(These will NOT be stored or logged.)\n")

    access_key = input("  AWS Access Key ID: ").strip()
    secret_key = input("  AWS Secret Access Key: ").strip()
    region = input("  AWS Region [us-east-1]: ").strip() or "us-east-1"

    if not access_key or not secret_key:
        print("Error: Both access key and secret key are required.")
        sys.exit(1)

    client = boto3.client(
        "s3",
        aws_access_key_id=access_key,
        aws_secret_access_key=secret_key,
        region_name=region,
    )
    return client


def list_bucket_files(client, bucket_name):
    """List all files in the specified S3 bucket."""
    print(f"\n{'='*60}")
    print(f"  Files in S3 bucket: {bucket_name}")
    print(f"{'='*60}\n")

    try:
        paginator = client.get_paginator("list_objects_v2")
        file_count = 0

        for page in paginator.paginate(Bucket=bucket_name):
            if "Contents" not in page:
                continue
            for obj in page["Contents"]:
                file_count += 1
                size_kb = obj["Size"] / 1024
                print(f"  {file_count:4d}. {obj['Key']:<50s}  "
                      f"{size_kb:>10.1f} KB  "
                      f"{obj['LastModified'].strftime('%Y-%m-%d %H:%M:%S')}")

        if file_count == 0:
            print("  (Bucket is empty)")
        else:
            print(f"\n  Total files: {file_count}")

    except ClientError as e:
        error_code = e.response["Error"]["Code"]
        if error_code == "NoSuchBucket":
            print(f"  Error: Bucket '{bucket_name}' does not exist.")
        elif error_code in ("AccessDenied", "403"):
            print(f"  Error: Access denied to bucket '{bucket_name}'. Check credentials/permissions.")
        else:
            print(f"  Error: {e}")
        sys.exit(1)


def main():
    print("\nAWS S3 Bucket Demo\n")
    client = get_s3_client()
    list_bucket_files(client, BUCKET_NAME)
    print()


if __name__ == "__main__":
    main()